+func captureStdout(t *testing.T, fn func() error) ([]byte, error) {
+	t.Helper()
+
+	oldStdout := os.Stdout
+	r, w, err := os.Pipe()
+	if err != nil {
+		t.Fatalf("os.Pipe error: %v", err)
+	}
+	os.Stdout = w
+
+	fnErr := fn()
+	_ = w.Close()
+	os.Stdout = oldStdout
+
+	out, readErr := io.ReadAll(r)
+	_ = r.Close()
+	if readErr != nil {
+		t.Fatalf("io.ReadAll error: %v", readErr)
+	}
+	return out, fnErr
+}

